import json
import boto3
import requests
from urllib.parse import urlparse

s3 = boto3.client('s3')

def lambda_handler(event, context):
    # Get the request headers from the event
    headers = event['Records'][0]['cf']['request']['headers']
    
    # Check if the X-Enrich-URL header is present in the request
    if 'X-Enrich-URL' in headers:
        # Get the URL from the header
        url = headers['X-Enrich-URL'][0]['value']
        
        # Make an HTTP GET request to the URL and fetch the response
        response = requests.get(url)
        
        # Check if the response is valid
        if response.status_code == 200:
            # Parse the JSON response from the URL
            data = json.loads(response.text)
            
            # Add the context data to the request headers
            headers['X-Enriched-Data'] = [{'value': json.dumps(data), 'key': 'X-Enriched-Data'}]
        
        # Forward the request to the origin with the updated headers
        return {
            'statusCode': 200,
            'headers': headers,
            'body': ''
        }
    else:
        # If the X-Enrich-URL header is not present, forward the request to the origin without any changes
        return {
            'statusCode': 200,
            'headers': headers,
            'body': ''
        }